"use client";

import { useRef, useEffect } from "react";
import "./particle-canvas.css";
import {
  HeroSection,
  AboutSection,
  ExperienceSection,
  ProjectsSection,
  SkillsSection,
  ContactSection,
} from "./sections";
import type { SectionConfig } from "./sections";

/* Section order */
const SECTIONS: SectionConfig[] = [
  HeroSection,
  AboutSection,
  ExperienceSection,
  ProjectsSection,
  SkillsSection,
  ContactSection,
];

/* ═══════════════════════════════════════
   Text-to-grid sampling
   Sample text at grid resolution — each hit = one block-sized particle
   ═══════════════════════════════════════ */
function sampleTextGrid(
  lines: string[],
  fontSize: number,
  lineHeight: number,
  letterSpacing: number,
  canvasW: number,
  canvasH: number,
  gridStep: number,
  fontFamily?: string,
): Array<{ gx: number; gy: number }> {
  const off = document.createElement("canvas");
  off.width = canvasW;
  off.height = canvasH;
  const ctx = off.getContext("2d")!;

  ctx.fillStyle = "#fff";
  const ff = fontFamily || "monospace";
  ctx.font = `400 ${fontSize}px ${ff}`;
  ctx.textBaseline = "top";

  /* Set letter-spacing if supported */
  try {
    (ctx as unknown as Record<string, string>).letterSpacing = `${letterSpacing}px`;
  } catch {
    /* fallback: no letter-spacing */
  }

  const lh = fontSize * lineHeight;
  const totalH = lines.length * lh;
  const startY = (canvasH - totalH) / 2;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (!line) continue;
    const metrics = ctx.measureText(line);
    const x = (canvasW - metrics.width) / 2;
    ctx.fillText(line, x, startY + i * lh);
  }

  const imageData = ctx.getImageData(0, 0, canvasW, canvasH);
  const hits: Array<{ gx: number; gy: number }> = [];

  const cols = Math.floor(canvasW / gridStep);
  const rows = Math.floor(canvasH / gridStep);

  /* For each grid cell, check if any text pixel exists */
  for (let gy = 0; gy < rows; gy++) {
    for (let gx = 0; gx < cols; gx++) {
      const cx = gx * gridStep + Math.floor(gridStep / 2);
      const cy = gy * gridStep + Math.floor(gridStep / 2);
      /* Sample a small area within the cell */
      let found = false;
      for (let dy = -Math.floor(gridStep / 3); dy <= Math.floor(gridStep / 3) && !found; dy += 2) {
        for (let dx = -Math.floor(gridStep / 3); dx <= Math.floor(gridStep / 3) && !found; dx += 2) {
          const sx = cx + dx;
          const sy = cy + dy;
          if (sx >= 0 && sx < canvasW && sy >= 0 && sy < canvasH) {
            const idx = (sy * canvasW + sx) * 4;
            if (imageData.data[idx + 3] > 30) {
              found = true;
            }
          }
        }
      }
      if (found) {
        hits.push({ gx, gy });
      }
    }
  }

  return hits;
}

/* ═══════════════════════════════════════
   Easing
   ═══════════════════════════════════════ */
function easeInOutCubic(t: number): number {
  return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
}

/* ═══════════════════════════════════════
   Particle type
   ═══════════════════════════════════════ */
interface SectionTarget {
  x: number;
  y: number;
  isText: boolean;
}

interface Particle {
  x: number;
  y: number;
  size: number;
  opacity: number;
  targets: SectionTarget[];
}

/* ═══════════════════════════════════════
   Component
   ═══════════════════════════════════════ */
export default function ParticleCanvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef(0);
  const indicatorRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d")!;
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    const W = window.innerWidth;
    const H = window.innerHeight;

    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = `${W}px`;
    canvas.style.height = `${H}px`;
    ctx.scale(dpr, dpr);

    const cX = W / 2;
    const cY = H / 2;

    /* Match EntryScreen block sizing */
    const blockSize = W < 600 ? 14 : W < 1024 ? 18 : 22;
    const gap = W < 600 ? 2 : 3;
    const gridStep = blockSize + gap;
    const cols = Math.floor(W / gridStep);
    const rows = Math.floor(H / gridStep);
    const oX = (W - cols * gridStep + gap) / 2;
    const oY = (H - rows * gridStep + gap) / 2;
    const N = cols * rows; /* Total grid cells = total particles */
    const totalSections = SECTIONS.length;

    /* Enable scrolling */
    document.body.style.overflow = "auto";
    document.body.style.overflowX = "hidden";
    document.body.style.height = `${totalSections * 100}vh`;

    /* Wait for fonts, then sample text and start animation */
    document.fonts.ready.then(() => {
      /* Resolve the actual font-family from CSS variable */
      const computedFont = getComputedStyle(document.documentElement)
        .getPropertyValue("--font-mono")
        .trim();
      const fontFamily = computedFont
        ? `${computedFont}, 'JetBrains Mono', monospace`
        : "'JetBrains Mono', 'SF Mono', monospace";
      console.log("[ParticleCanvas] font-family:", fontFamily);

      /* ── Sample text targets for each section ── */
      const sectionTargets: SectionTarget[][] = [];

      for (const section of SECTIONS) {
        const fontSize = Math.max(
          10,
          Math.round(section.fontSizeBase * Math.min(1, W / 1440)),
        );
        const textHits = sampleTextGrid(
          section.lines,
          fontSize,
          section.lineHeight,
          section.letterSpacing,
          W,
          H,
          gridStep,
          fontFamily,
        );
        console.log(`[ParticleCanvas] section "${section.label}": ${textHits.length} text blocks (fontSize=${fontSize})`);

        /* Build a set of text grid cells for quick lookup */
        const textSet = new Set(textHits.map((h) => `${h.gx},${h.gy}`));

        /* Build target array: one per grid cell */
        const targets: SectionTarget[] = [];
        for (let gy = 0; gy < rows; gy++) {
          for (let gx = 0; gx < cols; gx++) {
            const px = oX + gx * gridStep + blockSize / 2;
            const py = oY + gy * gridStep + blockSize / 2;
            targets.push({
              x: px,
              y: py,
              isText: textSet.has(`${gx},${gy}`),
            });
          }
        }

        sectionTargets.push(targets);
      }

      console.log(`[ParticleCanvas] Total sections: ${sectionTargets.length}, Particles: ${N}, Body height: ${totalSections * 100}vh`);

      /* ── Create particles — one per grid cell, same size as entry blocks ── */
      const particles: Particle[] = [];
      for (let i = 0; i < N; i++) {
        particles.push({
          x: cX + (Math.random() - 0.5) * 8,
          y: cY + (Math.random() - 0.5) * 8,
          size: blockSize,
          opacity: 0,
          targets: sectionTargets.map((st) => st[i]),
        });
      }

      /* ── Animation state ── */
      let lastScrollY = 0;
      let scrollVelocity = 0;
      let entryPhase = true;
      let entryStart = 0;
      const ENTRY_DUR = 2000;
      let time = 0;
      let currentLabel = SECTIONS[0].label;

      /* ── Section indicators (dots) ── */
      const dotEls = indicatorRef.current?.querySelectorAll<HTMLDivElement>(".pc-dot");

      /* ── RAF loop ── */
      const tick = (now: number) => {
        time = now * 0.001;

        const scrollY = window.scrollY;
        scrollVelocity =
          scrollVelocity * 0.85 + Math.abs(scrollY - lastScrollY) * 0.15;
        lastScrollY = scrollY;

        const sectionHeight = H;
        const progress = scrollY / sectionHeight;
        const sectionA = Math.min(
          Math.floor(progress),
          totalSections - 1,
        );
        const sectionB = Math.min(sectionA + 1, totalSections - 1);
        const t = sectionA === sectionB ? 0 : Math.min(1, progress - sectionA);
        const eased = easeInOutCubic(t);

        /* Transition chaos: particles scatter during scroll */
        const chaos = Math.sin(t * Math.PI) * Math.min(scrollVelocity * 0.4, 30);

        /* Update section label */
        const newLabel = t > 0.5 ? SECTIONS[sectionB].label : SECTIONS[sectionA].label;
        if (newLabel !== currentLabel) {
          currentLabel = newLabel;
          if (indicatorRef.current) {
            const labelEl =
              indicatorRef.current.querySelector<HTMLDivElement>(".pc-label");
            if (labelEl) labelEl.textContent = currentLabel;
          }
          /* Update dots */
          const activeIdx = t > 0.5 ? sectionB : sectionA;
          dotEls?.forEach((dot, idx) => {
            dot.classList.toggle("active", idx === activeIdx);
          });
        }

        /* ── Clear canvas ── */
        ctx.clearRect(0, 0, W, H);

        /* ── Update & draw particles ── */
        for (let i = 0; i < N; i++) {
          const p = particles[i];
          const fromT = p.targets[sectionA];
          const toT = p.targets[sectionB];

          /* Interpolate target */
          let tgtX = fromT.x * (1 - eased) + toT.x * eased;
          let tgtY = fromT.y * (1 - eased) + toT.y * eased;
          const isTextA = fromT.isText;
          const isTextB = toT.isText;
          let tgtOpacity = 0;

          /* Text particles are bright, ambient ones are very dim */
          const opaA = isTextA ? 0.85 : 0.018;
          const opaB = isTextB ? 0.85 : 0.018;
          tgtOpacity = opaA * (1 - eased) + opaB * eased;

          /* Organic noise during transition */
          if (chaos > 0.5) {
            tgtX += Math.sin(i * 0.37 + time * 3) * chaos;
            tgtY += Math.cos(i * 0.53 + time * 3) * chaos;
          }

          /* Center pull during mid-transition (moth-to-flame gather) */
          const centerPull = Math.sin(t * Math.PI) * 0.18;
          tgtX = tgtX * (1 - centerPull) + cX * centerPull;
          tgtY = tgtY * (1 - centerPull) + cY * centerPull;

          /* Entry animation: expand from center */
          if (entryPhase) {
            if (!entryStart) entryStart = now;
            const entryT = Math.min(1, (now - entryStart) / ENTRY_DUR);
            /* Per-particle stagger for wave-like expansion */
            const stagger = (i / N) * 0.35;
            const pT = Math.max(0, Math.min(1, (entryT - stagger) / (1 - stagger)));
            const entryEased = 1 - Math.pow(1 - pT, 3); /* easeOutCubic */
            tgtX = cX + (tgtX - cX) * entryEased;
            tgtY = cY + (tgtY - cY) * entryEased;
            tgtOpacity *= entryEased;
            if (entryT >= 1) entryPhase = false;
          }

          /* Smooth lerp toward target */
          const lerp = 0.065;
          p.x += (tgtX - p.x) * lerp;
          p.y += (tgtY - p.y) * lerp;
          p.opacity += (tgtOpacity - p.opacity) * 0.08;

          /* Tiny ambient drift for organic feel */
          p.x += Math.sin(time * 0.8 + i * 0.1) * 0.12;
          p.y += Math.cos(time * 0.6 + i * 0.15) * 0.12;

          /* Draw particle as a rounded dot (matches entry-screen border-radius: 50%) */
          if (p.opacity > 0.005) {
            ctx.globalAlpha = p.opacity;
            ctx.fillStyle = "#ffffff";
            const radius = p.size * 0.5;
            ctx.beginPath();
            ctx.arc(p.x, p.y, radius, 0, Math.PI * 2);
            ctx.fill();
          }
        }

        rafRef.current = requestAnimationFrame(tick);
      };

      rafRef.current = requestAnimationFrame(tick);
    });

    return () => {
      cancelAnimationFrame(rafRef.current);
      document.body.style.overflow = "";
      document.body.style.overflowX = "";
      document.body.style.height = "";
    };
  }, []);

  return (
    <>
      {/* Fixed particle canvas */}
      <canvas ref={canvasRef} className="pc-canvas" />

      {/* Section scroll spacers */}
      <div className="pc-sections">
        {SECTIONS.map((s, i) => (
          <section key={i} className="pc-section" data-section={i} />
        ))}
      </div>

      {/* Fixed section indicator */}
      <div ref={indicatorRef} className="pc-indicator">
        <div className="pc-label">{SECTIONS[0].label}</div>
        <div className="pc-dots">
          {SECTIONS.map((_, i) => (
            <div
              key={i}
              className={`pc-dot${i === 0 ? " active" : ""}`}
            />
          ))}
        </div>
      </div>
    </>
  );
}
